const body = $json.body ?? $json;

function cleanString(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function cleanLower(value) {
  return cleanString(value).toLowerCase();
}

function toBoolean(value) {
  if (typeof value === "boolean") return value;
  if (typeof value === "string") {
    return ["true", "yes", "1", "y"].includes(value.toLowerCase().trim());
  }
  return Boolean(value);
}

function toNumber(value) {
  const numberValue = Number(value);
  return Number.isFinite(numberValue) ? numberValue : null;
}

return {
  json: {
    raw: body,
    call: {
      call_id: cleanString(body.call_id),
      caller_name: cleanString(body.caller_name),
      caller_phone: cleanString(body.caller_phone),
      caller_email: cleanLower(body.caller_email),
      company: cleanString(body.company),
      call_intent: cleanLower(body.call_intent),
      urgency: cleanLower(body.urgency),
      callback_requested: toBoolean(body.callback_requested),
      preferred_callback_time: cleanString(body.preferred_callback_time),
      transcript: cleanString(body.transcript),
      summary: cleanString(body.summary),
      call_started_at: cleanString(body.call_started_at),
      call_duration_seconds: toNumber(body.call_duration_seconds),
      voice_platform: cleanLower(body.voice_platform),
      call_status: cleanLower(body.call_status)
    }
  }
};

const call = $json.call;
const errors = [];
const warnings = [];

function hasValue(value) {
  return value !== undefined && value !== null && String(value).trim() !== "";
}

if (!hasValue(call.call_id)) {
  errors.push("Missing call_id");
}

if (
  !hasValue(call.caller_name) &&
  !hasValue(call.caller_phone) &&
  !hasValue(call.caller_email)
) {
  errors.push("Missing caller identity");
}

if (
  !hasValue(call.call_intent) &&
  !hasValue(call.summary) &&
  !hasValue(call.transcript)
) {
  errors.push("Missing call intent, summary, or transcript");
}

if (!hasValue(call.voice_platform)) {
  errors.push("Missing voice_platform");
}

if (!hasValue(call.call_status)) {
  warnings.push("Missing call_status");
}

if (
  hasValue(call.caller_email) &&
  !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(call.caller_email)
) {
  warnings.push("caller_email format looks invalid");
}

if (
  call.call_duration_seconds !== null &&
  call.call_duration_seconds < 0
) {
  errors.push("call_duration_seconds cannot be negative");
}

if (
  hasValue(call.call_started_at) &&
  Number.isNaN(Date.parse(call.call_started_at))
) {
  warnings.push("call_started_at is not a valid timestamp");
}

const validation_status = errors.length > 0 ? "invalid" : "valid";

return {
  json: {
    ...$json,
    validation: {
      status: validation_status,
      errors,
      warnings
    }
  }
};

const call = $json.call;
const validation = $json.validation ?? { status: "valid", errors: [], warnings: [] };

const intentText = [
  call.call_intent,
  call.summary,
  call.transcript
].filter(Boolean).join(" ").toLowerCase();

const urgencyText = [
  call.urgency,
  call.summary,
  call.transcript
].filter(Boolean).join(" ").toLowerCase();

function includesAny(text, keywords) {
  return keywords.some((keyword) => text.includes(keyword));
}

const keywordGroups = {
  emergency: [
    "emergency",
    "urgent",
    "critical",
    "immediately",
    "asap",
    "system down",
    "is down",
    "outage",
    "cannot operate",
    "can't operate",
    "business stopped"
  ],
  sales: [
    "sales",
    "pricing",
    "quote",
    "demo",
    "proposal",
    "buy",
    "purchase",
    "consultation",
    "new service"
  ],
  support: [
    "support",
    "help",
    "issue",
    "problem",
    "broken",
    "not working",
    "technical",
    "error",
    "bug"
  ],
  billing: [
    "billing",
    "invoice",
    "payment",
    "charge",
    "refund",
    "subscription",
    "receipt"
  ],
  general: [
    "general",
    "question",
    "information",
    "follow up",
    "checking in"
  ]
};

let intent = "general";
let intent_reason = "Defaulted to general inquiry.";

if (includesAny(intentText, keywordGroups.emergency)) {
  intent = "emergency";
  intent_reason = "Emergency keywords found in call content.";
} else if (includesAny(intentText, keywordGroups.sales)) {
  intent = "sales";
  intent_reason = "Sales keywords found in call content.";
} else if (includesAny(intentText, keywordGroups.billing)) {
  intent = "billing";
  intent_reason = "Billing keywords found in call content.";
} else if (includesAny(intentText, keywordGroups.support)) {
  intent = "support";
  intent_reason = "Support keywords found in call content.";
} else if (includesAny(intentText, keywordGroups.general)) {
  intent = "general";
  intent_reason = "General inquiry keywords found in call content.";
}

let urgency = "low";
let urgency_reason = "Defaulted to low urgency.";

if (
  call.urgency === "emergency" ||
  includesAny(urgencyText, keywordGroups.emergency)
) {
  urgency = "emergency";
  urgency_reason = "Emergency urgency signal found.";
} else if (
  call.urgency === "high" ||
  includesAny(urgencyText, ["urgent", "asap", "today", "immediately"])
) {
  urgency = "high";
  urgency_reason = "High urgency signal found.";
} else if (
  call.urgency === "medium" ||
  includesAny(urgencyText, ["soon", "this week", "follow up"])
) {
  urgency = "medium";
  urgency_reason = "Medium urgency signal found.";
}

let route_key = "general_queue";

if (validation.status !== "valid") {
  route_key = "manual_review";
} else if (intent === "emergency" || urgency === "emergency" || urgency === "high") {
  route_key = "urgent_human_review";
} else if (intent === "sales") {
  route_key = "sales_follow_up";
} else if (intent === "support") {
  route_key = "support_queue";
} else if (intent === "billing") {
  route_key = "billing_queue";
}

return {
  json: {
    ...$json,
    classification: {
      intent,
      urgency,
      intent_reason,
      urgency_reason
    },
    routing: {
      route_key
    }
  }
};

const call = $json.call;
const validation = $json.validation;
const classification = $json.classification;
const routing = $json.routing;
const routeHandler = $json.route_handler;

function hasValue(value) {
  return value !== undefined && value !== null && String(value).trim() !== "";
}

return {
  json: {
    ...$json,
    call_log: {
      event_type: "ai_voice_call_routed",
      workflow_name: "AI Voice Ops Router",
      call_id: call.call_id,
      voice_platform: call.voice_platform,
      call_status: call.call_status,
      caller: {
        name: call.caller_name,
        company: call.company,
        phone_present: hasValue(call.caller_phone),
        email_present: hasValue(call.caller_email)
      },
      classification: {
        intent: classification.intent,
        urgency: classification.urgency,
        intent_reason: classification.intent_reason,
        urgency_reason: classification.urgency_reason
      },
      routing: {
        route_key: routing.route_key,
        route_name: routeHandler.route_name,
        owner_queue: routeHandler.owner_queue,
        priority: routeHandler.priority,
        sla: routeHandler.sla,
        notification_required: routeHandler.notification_required
      },
      validation: {
        status: validation.status,
        errors: validation.errors,
        warnings: validation.warnings
      },
      call: {
        started_at: call.call_started_at,
        duration_seconds: call.call_duration_seconds,
        callback_requested: call.callback_requested,
        preferred_callback_time: call.preferred_callback_time
      },
      summary: call.summary,
      processed_at: new Date().toISOString()
    }
  }
};

parameters.responseBody:
={{
{
  success: $json.validation.status === "valid",
  call_id: $json.call.call_id || null,
  route: $json.routing.route_key,
  route_name: $json.route_handler.route_name,
  classification: {
    intent: $json.classification.intent,
    urgency: $json.classification.urgency
  },
  validation_status: $json.validation.status,
  errors: $json.validation.errors,
  warnings: $json.validation.warnings,
  message: $json.validation.status === "valid"
    ? "Call received and routed."
    : "Call payload requires manual review."
}
}}
